local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxCrossWarTempleCtrl:LxBaseCtrl
local LxCrossWarTempleCtrl = classX("LxCrossWarTempleCtrl", LxBaseCtrl)

function LxCrossWarTempleCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
end

function LxCrossWarTempleCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end


function LxCrossWarTempleCtrl:GetInitWarDomainRef(refId)
    if not self._initWarDomainRef then
        self._initWarDomainRef = {}
    end
    local initWarDomainRef = self._initWarDomainRef[refId]
    if not initWarDomainRef then
        local ref = GameTable.BattleTempleDomainRef[refId]
        if ref then
            initWarDomainRef = {
                refId = refId,
                rank = ref.rank,
                rankReward = LxDataHelper.ParseItemStrList(ref.rankReward),
                holder = LxDataHelper.ParseItemStrList(ref.holder),
                protectNum = ref.protectNum,
                protectReward = LxDataHelper.ParseItemStrList(ref.protectReward,","),
                followNum = ref.followNum,
                followReward = LxDataHelper.ParseItemStrList(ref.followReward,","),
                seasonReward = LxDataHelper.ParseItemStrList(ref.seasonReward,","),
                monster = ref.monster,
                monsterShow = ref.monsterShow,
            }
            self._initWarDomainRef[refId] = initWarDomainRef
        end
    end
    return initWarDomainRef
end

---@param refId number WarDomainRef。refId
---@param type number 类型：1、殿主奖励；2、护佑奖励；3、追随奖励；4、殿外排名奖励；5、赛季奖励
---@return V_Item[]
function LxCrossWarTempleCtrl:GetWarDomainRewardList(refId,type)
    local initRef = self:GetInitWarDomainRef(refId)
    if not initRef then return {} end
    if type == 1 then
        return initRef.holder or {}
    elseif type == 2 then
        return initRef.protectReward or {}
    elseif type == 3 then
        return initRef.followReward or {}
    elseif type == 4 then
        return initRef.rankReward or {}
    elseif type == 5 then
        return initRef.seasonReward or {}
    end
    return {}
end

function LxCrossWarTempleCtrl:GetAllSeasonRewards()
    if not self._allSeasonRewards then
        local list = {}
        for k,v in pairs(GameTable.BattleTempleDomainRef) do
            local rewards = self:GetWarDomainRewardList(k,5)
            if rewards and #rewards > 0 then
                table.insert(list,{
                    rank = v.rank,
                    rewards = rewards,
                })
            end
        end
        table.sort(list,function(a,b)
            return a.rank < b.rank
        end)
        self._allSeasonRewards = list
    end
    return self._allSeasonRewards
end

