function LxCrossWarTempleCtrl:GetSeasonOpenTime()
    if not self._openWeek or not self._openTime then
        local seasonOpenTime = GameTable.BattleTempleConfigRef.seasonOpenTime
        seasonOpenTime = string.split(seasonOpenTime,",")
        self._openWeek = checknumber(seasonOpenTime[1])
        self._openTime = checknumber(seasonOpenTime[2]) * 60 * 60
    end
    return self._openWeek,self._openTime
end

function LxCrossWarTempleCtrl:GetSeasonEndTime()
    if not self._closeWeek or not self._closeTime then
        local seasonEndTime = GameTable.BattleTempleConfigRef.seasonEndTime
        seasonEndTime = string.split(seasonEndTime,",")
        self._closeWeek = checknumber(seasonEndTime[1])
        self._closeTime = checknumber(seasonEndTime[2]) * 60 * 60
    end
    return self._closeWeek,self._closeTime
end

function LxCrossWarTempleCtrl:GetStateAndLeftTime()
    local state = ModuleCenter.CrossWarTemple:GetCrossWarTempleState()
    local str = ""
    local leftTime = 0
    if state then
        if state:IsNoOpen() then
            local openWeek,openHour = self:GetSeasonOpenTime()
            local curDate = LxUtil.OSDate("*t", LxUtil.OSTime())
            local nowWeek = curDate.wday
            nowWeek = nowWeek == 0 and 8 or nowWeek
            local nowH = curDate.hour
            local nowM = curDate.min
            local nowS = curDate.sec
            local nowTick = (nowH * 60 * 60) + (nowM * 60) + nowS
            if openWeek < nowWeek or openHour - nowTick < 0 then
                openWeek = openWeek + 7
            end
            str = I18nText(8744)
            leftTime = (openWeek - nowWeek) * 86400 + (openHour - nowTick)
        elseif state:IsOpen() or state:IsSettlement() then
            str = I18nText(8744)
            leftTime = state.endTime - LxUtil.OSTime()
        end
    end
    return str, math.ceil(leftTime)
end

---@return number 返回
function LxCrossWarTempleCtrl:GetRetinueApplyNum()
    if not self._retinueApplyNum then
        self._retinueApplyNum = GameTable.BattleTempleConfigRef.retinueApplyNum
    end
    return self._retinueApplyNum
end


function LxCrossWarTempleCtrl:GetChallengeNumConsume1()
    if not self._challengeNumConsume1 then
        local list = {}
        local challengeNumConsume1 = GameTable.BattleTempleConfigRef.challengeNumConsume1
        challengeNumConsume1 = string.split(challengeNumConsume1,";")
        local iType = ThingType.Item
        for i,v in ipairs(challengeNumConsume1) do
            v = string.split(v,"=")
            table.insert(list,{
                type = iType,
                refId = Item_Ids.Diamond,
                num = checknumber(v[2]),
                payTime = checknumber(v[1]),
            })
        end
        self._challengeNumConsume1 = list
    end
    return self._challengeNumConsume1
end

function LxCrossWarTempleCtrl:GetMaxChallengeBuyNum()
    local data = self:GetChallengeNumConsume1()
    return #data
end

return LxCrossWarTempleCtrl